#include <iostream>
#include <fstream>
#include <string>
#include <sstream>
#include <algorithm>

using namespace std;

int main() {
    string filename, wordToFind;
    int count = 0;

    cout << "Enter the filename: ";
    cin >> filename;

    cout << "Enter the word to count: ";
    cin >> wordToFind;

    ifstream file(filename);

    if (file.is_open()) {
        string line;
        while (getline(file, line)) {
            // Convert the line to lowercase for case-insensitive search
            transform(line.begin(), line.end(), line.begin(), ::tolower);

            stringstream ss(line);
            string currentWord;

            while (ss >> currentWord) {
                if (currentWord == wordToFind) {
                    count++;
                }
            }
        }
        file.close();
    } else {
        cerr << "Unable to open file: " << filename << endl;
        return 1;
    }

    cout << "The word '" << wordToFind << "' appears " << count << " times in the file." << endl;

    return 0;
}
```

**Explanation:**

1. **Include Headers:**
   - `iostream`: For standard input/output operations (like `cin`, `cout`).
   - `fstream`: For file input/output operations (using `ifstream`).
   - `string`: For string manipulation.
   - `sstream`: For using `stringstream` to easily extract words from lines.
   - `algorithm`: For using `transform` to convert lines to lowercase.

2. **Get Input:**
   - Prompt the user to enter the filename and the word to search for.
   - Store these values in the `filename` and `wordToFind` variables.

3. **Open File:**
   - Create an `ifstream` object named `file` and attempt to open the specified file in read mode.
   - Check if the file opened successfully using `file.is_open()`. If not, print an error message and exit.

4. **Read Line by Line:**
   - Use a `while` loop and `getline(file, line)` to read each line from the file into the `line` string.

5. **Case-Insensitive Search:**
   - Convert each line to lowercase using `transform(line.begin(), line.end(), line.begin(), ::tolower)` to ensure case-insensitive matching.

6. **Extract Words from Line:**
   - Create a `stringstream` object `ss` initialized with the current `line`.
   - Use another `while` loop and `ss >> currentWord` to extract individual words from the `stringstream` and store them in the `currentWord` string.

7. **Count Occurrences:**
   - Inside the inner `while` loop, compare `currentWord` with `wordToFind`.
   - If they match, increment the `count` variable.

8. **Close File:**
   - After reading all lines, close the file using `file.close()`.

9. **Print Result:**
   - Print the final count of occurrences of `wordToFind` in the file.



